const express = require('express');
const multer = require('multer');
const xml2js = require('xml2js');
const fs = require('fs').promises;

const app = express();
const upload = multer({ 
  dest: 'uploads/',
  limits: { fileSize: 5 * 1024 * 1024 }
});

app.post('/api/upload-config', upload.single('xmlFile'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const xmlContent = await fs.readFile(req.file.path, 'utf8');

    const parserOptions = {
      explicitArray: false,
      ignoreAttrs: false,
      mergeAttrs: true,
      xmlns: false,
      explicitRoot: true,
      normalize: true,
      normalizeTags: false,
      trim: true,
      attrkey: 'attributes',
      charkey: 'value',
      explicitCharkey: false,
      validator: null,
      strict: true,
      async: false,
      xmldec: {
        version: '1.0',
        encoding: 'UTF-8',
        standalone: true
      }
    };

    const parser = new xml2js.Parser(parserOptions);

    const result = await parser.parseStringPromise(xmlContent);

    const configSettings = extractConfigSettings(result);

    await fs.unlink(req.file.path);

    res.json({
      success: true,
      configuration: configSettings,
      message: 'XML configuration processed successfully'
    });

  } catch (error) {
    if (req.file && req.file.path) {
      try {
        await fs.unlink(req.file.path);
      } catch (unlinkError) {
        console.error('Error deleting file:', unlinkError);
      }
    }

    console.error('Error processing XML:', error);
    res.status(400).json({
      success: false,
      error: 'Failed to process XML configuration',
      details: error.message
    });
  }
});

function extractConfigSettings(xmlObject) {
  const settings = {};

  function traverse(obj, path = '') {
    if (obj === null || obj === undefined) {
      return;
    }

    if (typeof obj === 'object' && !Array.isArray(obj)) {
      for (const [key, value] of Object.entries(obj)) {
        const newPath = path ? `${path}.${key}` : key;
        
        if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
          if (value.value !== undefined) {
            settings[newPath] = value.value;
          } else {
            traverse(value, newPath);
          }
        } else if (Array.isArray(value)) {
          settings[newPath] = value;
        } else {
          settings[newPath] = value;
        }
      }
    } else if (Array.isArray(obj)) {
      settings[path] = obj;
    } else {
      settings[path] = obj;
    }
  }

  traverse(xmlObject);
  return settings;
}

